import{_ as a,c as i,o as s,ah as r}from"./chunks/framework.C-x9UAyH.js";const b=JSON.parse('{"title":"Buenas Prácticas en el Diseño de Base de datos","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"postgresql/buenas_practicas.md","filePath":"postgresql/buenas_practicas.md","lastUpdated":1702158972000}'),o={name:"postgresql/buenas_practicas.md"};function l(n,e,t,d,p,c){return s(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="buenas-practicas-en-el-diseno-de-base-de-datos" tabindex="-1">Buenas Prácticas en el Diseño de Base de datos <a class="header-anchor" href="#buenas-practicas-en-el-diseno-de-base-de-datos" aria-label="Permalink to &quot;Buenas Prácticas en el Diseño de Base de datos&quot;">​</a></h1><h2 id="objetivos-de-un-buen-diseno" tabindex="-1">Objetivos de un buen diseño <a class="header-anchor" href="#objetivos-de-un-buen-diseno" aria-label="Permalink to &quot;Objetivos de un buen diseño&quot;">​</a></h2><ul><li>Minimizar la redundacia (usar normalización)</li><li>Proteger la precisión (no permitir &quot;basura&quot; en la bbdd)</li><li>Ser accesible (tener alta disponibilidad a la bbdd)</li><li>Cumplir las expectativas (resolver la necesidad)</li></ul><h2 id="principios-a-seguir" tabindex="-1">Principios a seguir <a class="header-anchor" href="#principios-a-seguir" aria-label="Permalink to &quot;Principios a seguir&quot;">​</a></h2><ul><li><p>Mantener la bbdd simple</p></li><li><p>Escribir todo en minúscula sin espacios</p></li><li><p>Usar estandarización (usar los mismos nombres de tablas, etc)</p></li><li><p>Se recomienda nombres de tablas en singular</p></li><li><p>Se recomienda nombres explicativos (explicitos)</p></li><li><p>Evitar nombres reservados como &quot;user&quot;, &quot;table&quot;, &quot;create&quot;</p></li><li><p>Establecer el tipo apropiado y precisión adecuados</p></li><li><p>Definir las llaves foraneas y relaciones</p></li><li><p>No usar abreviaturas</p></li><li><p>Normalizar la data (evitar redundancia)</p></li><li><p>Diseñar a largo plazo</p></li><li><p>Considerar futuras modificaciones</p></li><li><p>Mantener un modelado bajo versiones</p></li><li><p>Crear documentación y diagramas</p></li><li><p>Mantener la deuda técnica a raya (resolver a corto plazo errores)</p></li><li><p>Mantener la privacidad como prioridad</p></li><li><p>Probar el diseño</p></li><li><p>Mantener la bbdd en su propio servidor</p></li><li><p>No confiar en identificadores de terceros</p></li><li><p>Si el esquema es muy grande, se recomienda particionarlo</p></li></ul>',5)])])}const m=a(o,[["render",l]]);export{b as __pageData,m as default};
